def get_lang_from_path(path):
    parts = [p for p in path.split('/') if p]
    if parts and parts[0] in TRANSLATIONS:
        return parts[0]
    return 'fr'
def t_for(lang):
    return TRANSLATIONS.get(lang, TRANSLATIONS['fr'])
def lang_home(lang):
    slug = HOME_SLUGS.get(lang, 'accueil')
    return f'/{lang}/{slug}' if slug else f'/{lang}/'
def localized_url(page, lang):
    slug = PAGE_SLUGS.get(page, PAGE_SLUGS['home']).get(lang, '')
    return f'/{lang}/{slug}/' if slug else f'/{lang}/'
